#include <iostream>
using namespace std;

enum class Status { Active, Inactive, Pending, Banned };
enum class Priority { Low, Medium, High, Critical };

string statusName(Status s) {
    switch (s) {
        case Status::Active:   return "Active";
        case Status::Inactive: return "Inactive";
        case Status::Pending:  return "Pending";
        case Status::Banned:   return "Banned";
        default: return "Unknown";
    }
}

int main() {
    Status   myStatus   = Status::Active;
    Priority myPriority = Priority::High;

    cout << statusName(myStatus) << endl;

    // Can't mix types:
    // if (myStatus == myPriority)  // compile error!
    // int x = Status::Active;       // compile error!

    cout << "Type-safe!" << endl;

    return 0;
}

#include <iostream>
#include <string>
#include <cmath>
using namespace std;

struct Point {
    double x, y;
};

// const& avoids copying:
double distance(const Point& a, const Point& b) {
    double dx = a.x - b.x;
    double dy = a.y - b.y;
    return sqrt(dx*dx + dy*dy);
}

// Return struct by value (RVO optimises this):
Point midpoint(const Point& a, const Point& b) {
    return {(a.x + b.x) / 2, (a.y + b.y) / 2};
}

int main() {
    Point p1 = {0, 0};
    Point p2 = {6, 8};
    Point mid = midpoint(p1, p2);

    cout << distance(p1, p2) << endl;
    cout << mid.x << ", " << mid.y << endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
using namespace std;

struct Address {
    string street;
    string city;
    string country;
};

struct Employee {
    string name;
    int id;
    double salary;
    Address address;  // nested struct!
};

void printEmployee(const Employee& e) {
    cout << e.name << " (#" << e.id << ")" << endl;
    cout << "  City: " << e.address.city << endl;
    cout << "  Salary: $" << e.salary << endl;
}

int main() {
    Employee emp = {
        "Alice Smith", 1001, 95000.0,
        {"123 Main St", "San Francisco", "USA"}
    };

    printEmployee(emp);

    return 0;
}
